parameters.text:
={{ '⚠️ CHECK-CLOSE FALLIDO - Grid ' + $json.gridId + ' (' + $json.symbol + ')

Error: ' + $json.errorMessage + '

Se reintentara en el proximo ciclo (15 min).' }}

parameters.jsCode:
const resp = $json;
const ctx = $('Interpret Refresh Result').item.json;
const isError = resp.statusCode !== 200;
const body = resp.body || {};
return {
  json: {
    gridId: ctx.gridId,
    symbol: ctx.symbol,
    isError,
    statusCode: resp.statusCode,
    errorMessage: isError ? (body.detail || JSON.stringify(body)) : null,
    triggered: isError ? null : body.triggered,
    grid: isError ? null : body.grid
  }
};

